@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings
@using sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Services

<div class="settings-section">
    <h4>Profile</h4>
    <hr />

    <div class="avatar-area mb-4">
        <div class="avatar-preview">
            <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" width="96" height="96" />
        </div>
        <div class="mt-2">
            <label class="form-label">Avatar URL</label>
            <input type="text" class="form-control" @bind="AvatarUrl" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private string? StatusMessage;
    private bool IsError;
    private bool IsSaving;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            LoadFromProfile(Profile);
            _initialized = true;
        }
    }

    private bool _initialized;

    private void LoadFromProfile(UserProfile p)
    {
        DisplayName = p.DisplayName;
        Email = p.Email;
        AvatarUrl = p.AvatarUrl;
        Bio = p.Bio;
    }

    private async Task Save()
    {
        IsSaving = true;
        IsError = false;
        StatusMessage = null;
        try
        {
            var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Profile saved successfully!";
        }
        catch
        {
            StatusMessage = "Failed to save profile.";
            IsError = true;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
            StatusMessage = null;
        }
    }
}

@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings
@using sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Services

<div class="settings-section">
    <h4>Notifications</h4>
    <hr />

    <div class="mb-4">
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="emailNotif" @bind="EmailNotifications" />
            <label class="form-check-label" for="emailNotif">Email Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="pushNotif" @bind="PushNotifications" />
            <label class="form-check-label" for="pushNotif">Push Notifications</label>
        </div>
        <div class="form-check form-switch mb-3">
            <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="WeeklyDigest" />
            <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
        </div>
    </div>

    <h6>Muted Channels</h6>
    <div class="mb-4">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
            </div>
        }
    </div>

    @if (!string.IsNullOrEmpty(StatusMessage))
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @StatusMessage
            <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
        </div>
    }

    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private string? StatusMessage;
    private bool IsSaving;
    private bool _initialized;

    private static readonly List<string> AllChannels = ["announcements", "marketing", "product-updates", "community"];

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
            _initialized = true;
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        IsSaving = true;
        StatusMessage = null;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        StatusMessage = "Notification preferences saved!";
        IsSaving = false;
    }
}

@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="() => IsExpanded = !IsExpanded">
        <span>🔑 Change Password</span>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body mt-2">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }
            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success py-2">@SuccessMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@IsUpdating">
                @if (IsUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private string? SuccessMessage;
    private bool IsUpdating;

    private async Task UpdatePassword()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (NewPassword.Length < 6)
        {
            ErrorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "Passwords do not match.";
            return;
        }

        IsUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully!";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch
        {
            ErrorMessage = "Failed to update password.";
        }
        finally
        {
            IsUpdating = false;
        }
    }
}

