@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings

<div class="change-password-panel">
    <button class="btn btn-outline-secondary w-100 text-start d-flex justify-content-between align-items-center"
            @onclick="() => IsExpanded = !IsExpanded">
        <span>🔑 Change Password</span>
        <span>@(IsExpanded ? "▲" : "▼")</span>
    </button>

    @if (IsExpanded)
    {
        <div class="card card-body mt-2">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="CurrentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger py-2">@ErrorMessage</div>
            }
            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success py-2">@SuccessMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePassword" disabled="@IsUpdating">
                @if (IsUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = "";
    private string NewPassword = "";
    private string ConfirmPassword = "";
    private string? ErrorMessage;
    private string? SuccessMessage;
    private bool IsUpdating;

    private async Task UpdatePassword()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword))
        {
            ErrorMessage = "Current password is required.";
            return;
        }
        if (NewPassword.Length < 6)
        {
            ErrorMessage = "New password must be at least 6 characters.";
            return;
        }
        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "Passwords do not match.";
            return;
        }

        IsUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully!";
            CurrentPassword = "";
            NewPassword = "";
            ConfirmPassword = "";
        }
        catch
        {
            ErrorMessage = "Failed to update password.";
        }
        finally
        {
            IsUpdating = false;
        }
    }
}

