@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings
@using sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Services

<div class="appearance-preview card">
    <div class="card-body @ThemeClass @FontClass @(CompactMode ? "compact" : "")">
        <h6 class="card-title">Live Preview</h6>
        <p class="card-text">This is how your content will look with the selected settings.</p>
        <div class="d-flex gap-2 mt-2">
            <button class="btn btn-primary btn-sm">Primary</button>
            <button class="btn btn-outline-secondary btn-sm">Secondary</button>
        </div>
        <div class="mt-2">
            <small class="text-muted">Theme: @Theme | Font: @FontSize | Compact: @(CompactMode ? "On" : "Off")</small>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public bool CompactMode { get; set; }

    private string ThemeClass => Theme switch
    {
        "Dark" => "bg-dark text-light",
        "System" => "bg-secondary bg-opacity-10",
        _ => "bg-light text-dark"
    };

    private string FontClass => FontSize switch
    {
        "Small" => "fs-small",
        "Large" => "fs-large",
        _ => "fs-medium"
    };
}

@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings
@using sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Services

<div class="settings-section">
    <h4>Appearance</h4>
    <hr />

    <div class="mb-4">
        <h6>Theme</h6>
        @foreach (var theme in new[] { "Light", "Dark", "System" })
        {
            <div class="form-check">
                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                       value="@theme" checked="@(Theme == theme)"
                       @onchange="() => Theme = theme" />
                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
            </div>
        }
    </div>

    <div class="mb-4">
        <h6>Font Size</h6>
        @foreach (var size in new[] { "Small", "Medium", "Large" })
        {
            <div class="form-check">
                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                       value="@size" checked="@(FontSize == size)"
                       @onchange="() => FontSize = size" />
                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
            </div>
        }
    </div>

    <div class="mb-4">
        <h6>Language</h6>
        <select class="form-select" @bind="Language">
            @foreach (var lang in Languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <div class="mb-4">
        <div class="form-check form-switch">
            <input class="form-check-input" type="checkbox" id="compactMode" @bind="CompactMode" />
            <label class="form-check-label" for="compactMode">Compact Mode</label>
        </div>
    </div>

