arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@namespace sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Components.Pages.Settings
@using sv_1d7c7b8243184a9ebde6f40f1fe2e76f.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@ActiveSection" OnSectionChanged="SetSection" />

    <div class="settings-content">
        @if (IsLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    <ProfileSection Profile="@Profile" OnSave="SaveProfile" />
                    break;
                case "notifications":
                    <NotificationsSection Prefs="@NotificationPrefs" OnSave="SaveNotifications" />
                    break;
                case "security":
                    <SecuritySection Security="@Security"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession" />
                    break;
                case "appearance":
                    <AppearanceSection Settings="@Appearance" OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string ActiveSection = "profile";
    private bool IsLoading = true;

    private UserProfile? Profile;
    private NotificationPrefs? NotificationPrefs;
    private SecuritySettings? Security;
    private AppearanceSettings? Appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        IsLoading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        Profile = profileTask.Result;
        NotificationPrefs = notifsTask.Result;
        Security = securityTask.Result;
        Appearance = appearanceTask.Result;
    }

    private void SetSection(string section) => ActiveSection = section;

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        Profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        NotificationPrefs = prefs;
    }

    private async Task ChangePassword((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        Security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        Appearance = settings;
    }
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 70vh;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

/* Sidebar */
::deep .settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

::deep .sidebar-title {
    font-weight: 600;
    margin-bottom: 1rem;
    padding-left: 0.75rem;
    color: #495057;
}

::deep .settings-sidebar .nav-link {
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    padding: 0.6rem 0.75rem;
    border-radius: 0.375rem;
    color: #495057;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #f0f0f0;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: white;
}

/* Sections */
::deep .settings-section {
    max-width: 640px;
}

/* Avatar */
::deep .avatar-preview {
    display: inline-block;
    border: 3px solid #dee2e6;
    border-radius: 50%;
    overflow: hidden;
    width: 102px;
    height: 102px;
}

/* Appearance preview font sizes */
::deep .fs-small {
    font-size: 0.8rem;
}

::deep .fs-medium {
    font-size: 1rem;
}

::deep .fs-large {
    font-size: 1.2rem;
}

::deep .compact p,
::deep .compact .card-text {
    margin-bottom: 0.25rem;
    line-height: 1.2;
}

::deep .appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
}

/* Modal backdrop */
::deep .modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 1040;
}

::deep .modal {
    z-index: 1050;
}

/* Responsive */
@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    ::deep .settings-sidebar {
        width: 100%;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding-right: 0;
        padding-bottom: 1rem;
    }

    ::deep .settings-sidebar .nav {
        flex-direction: row !important;
        overflow-x: auto;
    }

    ::deep .settings-sidebar .nav-item {
        white-space: nowrap;
    }
}

